import hashlib
from datetime import datetime, timedelta, timezone
from typing import Optional
import uuid

from fastapi import Depends, HTTPException, Request, Response
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from jose import JWTError, jwt
from passlib.context import CryptContext
from sqlalchemy import select
from sqlalchemy.ext.asyncio import AsyncSession
from sqlalchemy.orm import selectinload

from app.core.config import settings
from app.core.database import get_db
from app.models.db_models import User, UserSettings

pwd_context = CryptContext(schemes=["bcrypt"], deprecated="auto")
security = HTTPBearer(auto_error=False)


def hash_password(password: str) -> str:
    return pwd_context.hash(password)


def verify_password(plain: str, hashed: str) -> bool:
    return pwd_context.verify(plain, hashed)


def create_access_token(user_id: str) -> str:
    expire = datetime.now(timezone.utc) + timedelta(days=settings.JWT_EXPIRES_DAYS)
    payload = {"sub": user_id, "exp": expire}
    return jwt.encode(payload, settings.JWT_SECRET, algorithm=settings.JWT_ALGORITHM)


def decode_token(token: str) -> Optional[str]:
    try:
        payload = jwt.decode(token, settings.JWT_SECRET, algorithms=[settings.JWT_ALGORITHM])
        return payload.get("sub")
    except JWTError:
        return None


def set_auth_cookie(response: Response, token: str):
    response.set_cookie(
        key="auth_token",
        value=token,
        max_age=settings.JWT_EXPIRES_DAYS * 86400,
        httponly=True,
        secure=False,  # Set True in production with HTTPS
        samesite="lax",
    )


def clear_auth_cookie(response: Response):
    response.delete_cookie(key="auth_token", httponly=True, samesite="lax")


async def get_current_user(
    request: Request,
    db: AsyncSession = Depends(get_db),
) -> Optional[User]:
    token = request.cookies.get("auth_token")
    if not token:
        return None
    user_id = decode_token(token)
    if not user_id:
        return None
    result = await db.execute(
        select(User).where(User.id == user_id, User.deleted_at.is_(None))
    )
    user = result.scalar_one_or_none()
    return user


async def require_user(current_user: Optional[User] = Depends(get_current_user)) -> User:
    if current_user is None:
        raise HTTPException(status_code=401, detail="Authentication required")
    return current_user


async def get_or_create_settings(db: AsyncSession, user_id: str) -> UserSettings:
    result = await db.execute(
        select(UserSettings).where(UserSettings.user_id == user_id)
    )
    settings_obj = result.scalar_one_or_none()
    if not settings_obj:
        settings_obj = UserSettings(
            id="us_" + uuid.uuid4().hex[:12],
            user_id=user_id,
        )
        db.add(settings_obj)
        await db.flush()
    return settings_obj

"""
Doubao / Volcengine Realtime API binary protocol handler.

Frame format (4 bytes header + payload):
- Byte 0: Protocol Version (1)
- Byte 1: Header Size (always 1 for no compression)
- Byte 2: Message Type (0b0001=TextControl, 0b0010=AudioData)
- Byte 3: 0 or 1 (compression flag + reserved)
- Bytes 4+: JSON payload or raw audio data
"""

import struct
import json
import gzip
from enum import IntEnum
from typing import Optional, Tuple


class MessageType(IntEnum):
    TEXT_CONTROL = 0b0001
    AUDIO_DATA = 0b0010


class CompressionType(IntEnum):
    NONE = 0
    GZIP = 1


def pack_frame(msg_type: MessageType, payload: bytes, compress: bool = False) -> bytes:
    """Pack a binary frame according to Doubao protocol."""
    version = 1
    header_size = 1
    compression = CompressionType.GZIP if compress else CompressionType.NONE

    if compress:
        payload = gzip.compress(payload)

    # Byte 3: compression flag in bit 4 (0b00010000)
    byte3 = (compression << 4) | 0

    header = struct.pack("!BBBB", version, header_size, int(msg_type), byte3)
    return header + payload


def unpack_frame(data: bytes) -> Optional[Tuple[MessageType, bytes]]:
    """Unpack a binary frame. Returns (MessageType, payload) or None if incomplete."""
    if len(data) < 4:
        return None

    version = data[0]
    header_size = data[1]
    msg_type = data[2]
    byte3 = data[3]

    compression = (byte3 >> 4) & 0x0F

    if version != 1:
        raise ValueError(f"Unsupported protocol version: {version}")

    payload = data[4:]

    if compression == CompressionType.GZIP:
        payload = gzip.decompress(payload)

    try:
        msg_type_enum = MessageType(msg_type)
    except ValueError:
        raise ValueError(f"Unknown message type: {msg_type}")

    return (msg_type_enum, payload)


def pack_text_control(data: dict) -> bytes:
    """Pack a JSON text control message into a binary frame."""
    payload = json.dumps(data, ensure_ascii=False).encode("utf-8")
    return pack_frame(MessageType.TEXT_CONTROL, payload)


def pack_audio_data(audio_bytes: bytes) -> bytes:
    """Pack raw audio data into a binary frame."""
    return pack_frame(MessageType.AUDIO_DATA, audio_bytes)


def unpack_text_control(payload: bytes) -> dict:
    """Unpack a text control payload into a dict."""
    return json.loads(payload.decode("utf-8"))


def create_start_session(
    speaker: str = "vv",
    model_type: str = "dialog",
) -> bytes:
    """Create StartSession message."""
    msg = {
        "type": "StartSession",
        "data": {
            "speaker": speaker,
            "model_type": model_type,
            "app_id": "",
            "access_key": "",
            "resource_id": "volc.speech.dialog",
        }
    }
    return pack_text_control(msg)


def create_finish_session() -> bytes:
    """Create FinishSession message."""
    return pack_text_control({"type": "FinishSession", "data": {}})


def create_finish_connection() -> bytes:
    """Create FinishConnection message."""
    return pack_text_control({"type": "FinishConnection", "data": {}})


def create_end_asr() -> bytes:
    """Create EndASR message."""
    return pack_text_control({"type": "EndASR", "data": {}})


def create_client_interrupt() -> bytes:
    """Create ClientInterrupt message."""
    return pack_text_control({"type": "ClientInterrupt", "data": {}})


def create_update_config(speaker: str) -> bytes:
    """Create UpdateConfig message for changing TTS speaker."""
    return pack_text_control({
        "type": "UpdateConfig",
        "data": {
            "tts": {
                "speaker": speaker,
            }
        }
    })

"""
WebSocket voice proxy for Doubao Realtime API.
"""

import asyncio
import json
import base64
import struct
import traceback
from typing import Optional

import websockets
from fastapi import APIRouter, WebSocket, WebSocketDisconnect
from websockets.asyncio.client import connect as ws_connect

from app.core.config import settings
from app.ws.doubao_protocol import (
    pack_frame, unpack_frame, MessageType,
    pack_text_control, pack_audio_data,
    unpack_text_control,
    create_start_session, create_finish_session,
    create_finish_connection, create_end_asr,
    create_client_interrupt, create_update_config,
)

router = APIRouter(tags=["voice"])


async def doubao_connection(speaker: str = "vv"):
    """Create a connection to Doubao Realtime API."""
    headers = {
        "X-Api-App-Id": settings.VOICE_APP_ID,
        "X-Api-Access-Key": settings.VOICE_ACCESS_KEY,
        "X-Api-Resource-Id": settings.VOICE_RESOURCE_ID,
        "X-Api-App-Key": settings.VOICE_APP_KEY,
    }

    ws = await ws_connect(
        settings.VOICE_WS_URL,
        additional_headers=headers,
        ping_interval=20,
        ping_timeout=10,
    )

    # Send StartSession
    await ws.send(create_start_session(speaker=speaker))

    return ws


@router.websocket("/voice/ws")
async def voice_websocket(websocket: WebSocket):
    await websocket.accept()
    print("[Voice] Client connected")

    doubao_ws: Optional[websockets.WebSocketClientProtocol] = None
    speaker = "vv"
    session_started = False

    # Task for forwarding from Doubao to client
    doubao_to_client_task: Optional[asyncio.Task] = None

    async def forward_doubao_to_client():
        """Forward messages from Doubao to the frontend client."""
        nonlocal session_started
        try:
            while doubao_ws:
                try:
                    raw = await asyncio.wait_for(doubao_ws.recv(), timeout=30.0)
                except asyncio.TimeoutError:
                    # Send ping to keep alive
                    if doubao_ws:
                        try:
                            await doubao_ws.ping()
                        except Exception:
                            break
                    continue

                if isinstance(raw, str):
                    # Text message from Doubao - sometimes they send JSON directly
                    try:
                        data = json.loads(raw)
                        msg_type = data.get("type", "Unknown")
                        await websocket.send_json({
                            "type": msg_type,
                            "data": data.get("data", {}),
                        })
                    except json.JSONDecodeError:
                        pass
                elif isinstance(raw, bytes):
                    # Binary frame from Doubao
                    try:
                        msg_type, payload = unpack_frame(raw)
                    except Exception as e:
                        print(f"[Voice] Failed to unpack Doubao frame: {e}")
                        continue

                    if msg_type == MessageType.TEXT_CONTROL:
                        data = unpack_text_control(payload)
                        msg_type_str = data.get("type", "Unknown")

                        if msg_type_str == "StartSessionResponse":
                            session_started = True
                            await websocket.send_json({
                                "type": "SessionStarted",
                                "data": data.get("data", {}),
                            })
                        elif msg_type_str == "TTSResponse":
                            audio_data = data.get("data", {}).get("audio", "")
                            await websocket.send_json({
                                "type": "TTSResponse",
                                "data": audio_data,  # base64 audio
                            })
                        elif msg_type_str == "ASRResponse":
                            await websocket.send_json({
                                "type": "ASRResponse",
                                "data": data.get("data", {}),
                            })
                        elif msg_type_str == "ChatResponse":
                            await websocket.send_json({
                                "type": "ChatResponse",
                                "data": data.get("data", {}),
                            })
                        elif msg_type_str == "FinishSessionResponse":
                            await websocket.send_json({
                                "type": "SessionFinished",
                                "data": {},
                            })
                        else:
                            await websocket.send_json({
                                "type": msg_type_str,
                                "data": data.get("data", {}),
                            })
                    elif msg_type == MessageType.AUDIO_DATA:
                        # Raw audio - send as base64
                        await websocket.send_json({
                            "type": "TTSResponse",
                            "data": base64.b64encode(payload).decode("utf-8"),
                        })

        except websockets.exceptions.ConnectionClosed:
            pass
        except Exception as e:
            print(f"[Voice] Doubao→Client error: {e}")
            traceback.print_exc()

    try:
        while True:
            # Receive message from frontend
            data = await websocket.receive()

            if "text" in data:
                # JSON text message from frontend
                try:
                    msg = json.loads(data["text"])
                    msg_type = msg.get("type", "")
                except json.JSONDecodeError:
                    continue

                if msg_type == "StartSession":
                    # Connect to Doubao
                    speaker = msg.get("data", {}).get("speaker", "vv")
                    if doubao_ws:
                        await doubao_ws.close()
                    doubao_ws = await doubao_connection(speaker=speaker)
                    session_started = False

                    # Start forwarding task
                    if doubao_to_client_task and not doubao_to_client_task.done():
                        doubao_to_client_task.cancel()
                    doubao_to_client_task = asyncio.create_task(forward_doubao_to_client())

                elif msg_type == "FinishSession":
                    if doubao_ws and session_started:
                        await doubao_ws.send(create_finish_session())
                    session_started = False

                elif msg_type == "FinishConnection":
                    if doubao_ws:
                        await doubao_ws.send(create_finish_connection())
                    break

                elif msg_type == "EndASR":
                    if doubao_ws:
                        await doubao_ws.send(create_end_asr())

                elif msg_type == "ClientInterrupt":
                    if doubao_ws:
                        await doubao_ws.send(create_client_interrupt())
                        # Also notify client that interrupt was sent
                        await websocket.send_json({"type": "InterruptAck", "data": {}})

                elif msg_type == "UpdateConfig":
                    new_speaker = msg.get("data", {}).get("tts", {}).get("speaker")
                    if new_speaker and doubao_ws:
                        speaker = new_speaker
                        await doubao_ws.send(create_update_config(new_speaker))

                else:
                    # Generic text control - forward as-is
                    if doubao_ws:
                        await doubao_ws.send(pack_text_control(msg))

            elif "bytes" in data:
                # Binary audio data from frontend
                if doubao_ws:
                    audio_bytes = data["bytes"]
                    await doubao_ws.send(pack_audio_data(audio_bytes))

    except WebSocketDisconnect:
        print("[Voice] Client disconnected")
    except Exception as e:
        print(f"[Voice] Error: {e}")
        traceback.print_exc()
    finally:
        # Cleanup
        if doubao_to_client_task and not doubao_to_client_task.done():
            doubao_to_client_task.cancel()
        if doubao_ws:
            try:
                await doubao_ws.send(create_finish_connection())
                await doubao_ws.close()
            except Exception:
                pass
        try:
            await websocket.close()
        except Exception:
            pass

