import { useEffect, useRef, useState } from 'react';
import { useUIStore, useConversationStore, useAuthStore, useModelStore } from '../../store';
import MessageBubble from './MessageBubble';
import ChatInput from './ChatInput';
import LoadingDots from '../common/LoadingDots';
import type { Message } from '../../types';

export default function ChatView() {
  const { currentConversationId } = useUIStore();
  const {
    currentMessages, isLoadingMessages, isStreaming, streamingContent,
    fetchMessages, sendChatMessage, stopStreaming, clearMessages,
  } = useConversationStore();
  const { selectedModelId } = useModelStore();
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const messagesContainerRef = useRef<HTMLDivElement>(null);
  const [showScrollButton, setShowScrollButton] = useState(false);
  const [isUserScrolling, setIsUserScrolling] = useState(false);

  // Load messages when conversation changes
  useEffect(() => {
    if (currentConversationId) {
      fetchMessages(currentConversationId);
    } else {
      clearMessages();
    }
  }, [currentConversationId]);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    if (!isUserScrolling) {
      scrollToBottom();
    }
  }, [currentMessages, streamingContent]);

  const scrollToBottom = (smooth = true) => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: smooth ? 'smooth' : 'auto' });
    }
    setShowScrollButton(false);
    setIsUserScrolling(false);
  };

  const handleScroll = () => {
    const container = messagesContainerRef.current;
    if (!container) return;
    const isNearBottom = container.scrollHeight - container.scrollTop - container.clientHeight < 100;
    setShowScrollButton(!isNearBottom);
    if (isNearBottom) setIsUserScrolling(false);
    else setIsUserScrolling(true);
  };

  const handleSendMessage = async (text: string, imageUrls?: string[]) => {
    let convId = currentConversationId;
    if (!convId) {
      // Create new conversation
      const guestId = useAuthStore.getState().guestId;
      const headers: Record<string, string> = { 'Content-Type': 'application/json' };
      if (guestId && !useAuthStore.getState().isLoggedIn) {
        headers['x-guest-id'] = guestId;
      }
      try {
        const resp = await fetch('/api/conversations', {
          method: 'POST',
          credentials: 'include',
          headers,
          body: JSON.stringify({ title: text.slice(0, 30), mode: 'chat', model_id: selectedModelId }),
        });
        if (resp.ok) {
          const conv = await resp.json();
          convId = conv.id;
          useUIStore.getState().setCurrentConversationId(conv.id);
        }
      } catch (e) {
        console.error(e);
        return;
      }
    }

    if (convId) {
      await sendChatMessage(convId, text, selectedModelId, imageUrls);
    }
  };

  return (
    <div className="h-full flex flex-col">
      {/* Messages area */}
      <div
        ref={messagesContainerRef}
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto px-4 py-4"
      >
        <div className="max-w-chat mx-auto">
          {!currentConversationId && currentMessages.length === 0 && (
            <div className="flex flex-col items-center justify-center py-20 text-center">
              <div className="w-20 h-20 rounded-full bg-primary-100 flex items-center justify-center mb-6">
                <svg className="w-10 h-10 text-primary-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
                </svg>
              </div>
              <h2 className="text-xl font-bold text-gray-700 mb-2">开始对话</h2>
              <p className="text-gray-400 text-sm max-w-xs">
                在下方输入你想了解的内容，AI 将为你提供帮助
              </p>
            </div>
          )}

          {isLoadingMessages && (
            <div className="flex justify-center py-8">
              <LoadingDots />
            </div>
          )}

          {currentMessages.map((msg) => (
            <MessageBubble key={msg.id} message={msg} />
          ))}

          {/* Streaming message */}
          {isStreaming && streamingContent && (
            <MessageBubble
              message={{
                id: 'streaming',
                conversation_id: currentConversationId || '',
                role: 'assistant',
                content: streamingContent,
                status: 'sending',
                created_at: new Date().toISOString(),
              }}
              isStreaming
            />
          )}

          {isStreaming && !streamingContent && (
            <div className="flex justify-start mb-4">
              <div className="bg-gray-100 rounded-2xl rounded-bl-md px-4 py-3">
                <LoadingDots />
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>
      </div>

      {/* Scroll to bottom button */}
      {showScrollButton && (
        <button
          onClick={() => scrollToBottom(true)}
          className="absolute bottom-24 right-6 w-10 h-10 rounded-full bg-primary-500 text-white shadow-lg flex items-center justify-center hover:bg-primary-600 transition-colors z-10"
          aria-label="回到底部"
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
          </svg>
        </button>
      )}

      {/* Input area */}
      <ChatInput
        onSend={handleSendMessage}
        onStop={stopStreaming}
        isStreaming={isStreaming}
      />
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeHighlight from 'rehype-highlight';
import rehypeKatex from 'rehype-katex';
import type { Message as MessageType } from '../../types';
import { useConversationStore, useUIStore } from '../../store';

interface Props {
  message: MessageType;
  isStreaming?: boolean;
}

export default function MessageBubble({ message, isStreaming }: Props) {
  const isUser = message.role === 'user';
  const [showMenu, setShowMenu] = useState(false);
  const [isLongPress, setIsLongPress] = useState(false);
  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const { deleteMessage } = useConversationStore();
  const { showToast } = useUIStore();

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(message.content);
      showToast('已复制到剪贴板', 'success');
    } catch {
      showToast('复制失败', 'error');
    }
    setShowMenu(false);
  };

  const handleDelete = async () => {
    if (confirm('确认删除这条消息？')) {
      await deleteMessage(message.id);
    }
    setShowMenu(false);
  };

  // Touch handlers for long press
  const handleTouchStart = () => {
    longPressTimer.current = setTimeout(() => {
      setIsLongPress(true);
      setShowMenu(true);
    }, 600);
  };

  const handleTouchEnd = () => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }
  };

  useEffect(() => {
    return () => {
      if (longPressTimer.current) clearTimeout(longPressTimer.current);
    };
  }, []);

  return (
    <div
      className={`flex mb-4 ${isUser ? 'justify-end' : 'justify-start'}`}
      onMouseEnter={() => !isUser && setShowMenu(true)}
      onMouseLeave={() => !isLongPress && setShowMenu(false)}
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
    >
      <div className={`relative max-w-[85%] md:max-w-[75%] ${isUser ? 'order-1' : 'order-1'}`}>
        {/* Message bubble */}
        <div
          className={`px-4 py-3 rounded-2xl text-sm leading-relaxed ${
            isUser
              ? 'bg-primary-500 text-white rounded-br-md'
              : 'bg-white text-gray-800 rounded-bl-md shadow-sm border border-gray-100'
          }`}
        >
          {isUser ? (
            // User message - plain text with inline images
            <div className="whitespace-pre-wrap break-words">{message.content}</div>
          ) : (
            // Assistant message - Markdown rendered
            <div className="markdown-body">
              <ReactMarkdown
                remarkPlugins={[remarkGfm, remarkMath]}
                rehypePlugins={[rehypeHighlight, rehypeKatex]}
              >
                {message.content}
              </ReactMarkdown>
              {isStreaming && (
                <span className="inline-block w-2 h-4 bg-primary-500 animate-pulse ml-0.5 align-text-bottom" />
              )}
            </div>
          )}
        </div>

        {/* Action menu */}
        {showMenu && !isUser && !isStreaming && (
          <div
            className={`absolute ${isUser ? 'right-0' : 'left-0'} -bottom-9 flex gap-1 bg-white rounded-lg shadow-lg border border-gray-100 px-1.5 py-1 z-10`}
          >
            <button onClick={handleCopy} className="p-1.5 rounded hover:bg-gray-100 text-gray-500 hover:text-primary-600" title="复制">
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
              </svg>
            </button>
            <button onClick={handleDelete} className="p-1.5 rounded hover:bg-red-50 text-gray-500 hover:text-red-500" title="删除">
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
            </button>
          </div>
        )}

        {/* Timestamp */}
        {message.created_at && !isStreaming && (
          <div className={`text-[10px] text-gray-400 mt-1 ${isUser ? 'text-right' : 'text-left'}`}>
            {new Date(message.created_at).toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' })}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { useModelStore, useUIStore } from '../../store';

interface Props {
  onSend: (text: string, imageUrls?: string[]) => void;
  onStop: () => void;
  isStreaming: boolean;
}

export default function ChatInput({ onSend, onStop, isStreaming }: Props) {
  const [text, setText] = useState('');
  const [imageUrls, setImageUrls] = useState<string[]>([]);
  const [uploading, setUploading] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { models, selectedModelId, setSelectedModel } = useModelStore();
  const { showModelSelector, setShowModelSelector, showToast } = useUIStore();

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 150) + 'px';
    }
  }, [text]);

  // Focus on mount and when mode switches
  useEffect(() => {
    textareaRef.current?.focus();
  }, []);

  const handleSend = () => {
    const trimmed = text.trim();
    if (!trimmed || isStreaming) return;
    onSend(trimmed, imageUrls.length > 0 ? imageUrls : undefined);
    setText('');
    setImageUrls([]);
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setUploading(true);
    try {
      for (const file of Array.from(files)) {
        const formData = new FormData();
        formData.append('file', file);
        const resp = await fetch('/api/upload/image', {
          method: 'POST',
          credentials: 'include',
          body: formData,
        });
        if (resp.ok) {
          const data = await resp.json();
          setImageUrls((prev) => [...prev, data.url]);
        }
      }
    } catch {
      showToast('上传失败', 'error');
    }
    setUploading(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const selectedModel = models.find((m) => m.id === selectedModelId);

  return (
    <div className="flex-shrink-0 px-3 pb-3 pt-1">
      <div className="max-w-chat mx-auto">
        <div className="bg-white rounded-2xl shadow-lg border border-primary-100">
          {/* Image previews */}
          {imageUrls.length > 0 && (
            <div className="flex gap-2 px-4 pt-3 flex-wrap">
              {imageUrls.map((url, idx) => (
                <div key={idx} className="relative group">
                  <img src={url} alt="" className="w-16 h-16 object-cover rounded-lg border" />
                  <button
                    onClick={() => setImageUrls((prev) => prev.filter((_, i) => i !== idx))}
                    className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-red-500 text-white rounded-full flex items-center justify-center text-xs opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    ×
                  </button>
                </div>
              ))}
            </div>
          )}

          {/* Text input */}
          <div className="flex items-end gap-2 px-3 py-2">
            <textarea
              ref={textareaRef}
              value={text}
              onChange={(e) => setText(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="输入消息..."
              rows={1}
              className="flex-1 resize-none bg-transparent text-sm text-gray-800 placeholder-gray-400 focus:outline-none py-2 max-h-[150px]"
              disabled={isStreaming}
            />

            <div className="flex items-center gap-1 flex-shrink-0">
              {/* Upload button */}
              <button
                onClick={() => fileInputRef.current?.click()}
                disabled={uploading}
                className="p-2 rounded-lg text-gray-400 hover:text-primary-500 hover:bg-primary-50 transition-colors"
                title="上传图片"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                </svg>
              </button>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                multiple
                className="hidden"
                onChange={handleUpload}
              />

              {/* Send / Stop button */}
              {isStreaming ? (
                <button
                  onClick={onStop}
                  className="p-2 rounded-lg bg-red-500 text-white hover:bg-red-600 transition-colors"
                  title="停止生成"
                >
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                    <rect x="6" y="6" width="12" height="12" rx="2" />
                  </svg>
                </button>
              ) : (
                <button
                  onClick={handleSend}
                  disabled={!text.trim()}
                  className="p-2 rounded-lg bg-primary-500 text-white hover:bg-primary-600 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                  title="发送"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                  </svg>
                </button>
              )}
            </div>
          </div>

          {/* Bottom bar: model selector */}
          <div className="flex items-center px-3 pb-2">
            <button
              onClick={() => setShowModelSelector(!showModelSelector)}
              className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs text-gray-500 hover:bg-primary-50 hover:text-primary-600 transition-colors"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.75 17L9 20l-1 1h8l-1-1-.75-3M3 13h18M5 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
              {selectedModel?.name || '选择模型'}
            </button>

            {showModelSelector && (
              <ModelSelector onClose={() => setShowModelSelector(false)} />
            )}
          </div>
        </div>

        <p className="text-[10px] text-center text-gray-400 mt-1.5">
          AI 生成内容可能不准确，请核实重要信息
        </p>
      </div>
    </div>
  );
}

function ModelSelector({ onClose }: { onClose: () => void }) {
  const { models, selectedModelId, setSelectedModel } = useModelStore();
  const [search, setSearch] = useState('');

  const filtered = models.filter(
    (m) =>
      m.name.toLowerCase().includes(search.toLowerCase()) ||
      m.id.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="absolute bottom-full left-3 mb-2 w-72 max-h-80 bg-white rounded-xl shadow-xl border border-gray-200 overflow-hidden z-20">
      <div className="p-2 border-b border-gray-100">
        <input
          type="text"
          placeholder="搜索模型..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full px-3 py-1.5 text-sm rounded-lg bg-gray-50 focus:outline-none focus:ring-1 focus:ring-primary-300"
          autoFocus
        />
      </div>
      <div className="overflow-y-auto max-h-60">
        {filtered.map((m) => (
          <button
            key={m.id}
            onClick={() => {
              setSelectedModel(m.id);
              onClose();
            }}
            className={`w-full text-left px-3 py-2.5 text-sm hover:bg-primary-50 transition-colors flex items-center justify-between ${
              m.id === selectedModelId ? 'bg-primary-50 text-primary-700' : 'text-gray-700'
            }`}
          >
            <span className="truncate">{m.name}</span>
            {m.id === selectedModelId && (
              <svg className="w-4 h-4 text-primary-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
            )}
          </button>
        ))}
      </div>
    </div>
  );
}

import { useState, useRef, useCallback, useEffect } from 'react';
import { useUIStore } from '../../store';

type VoiceState = 'idle' | 'connecting' | 'listening' | 'processing' | 'speaking';

export default function VoiceView() {
  const [state, setState] = useState<VoiceState>('idle');
  const [transcript, setTranscript] = useState('');
  const [responseText, setResponseText] = useState('');
  const [volume, setVolume] = useState(0);
  const [error, setError] = useState('');

  const wsRef = useRef<WebSocket | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const audioQueueRef = useRef<AudioBuffer[]>([]);
  const isPlayingRef = useRef(false);
  const isPressingRef = useRef(false);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const volIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const { showToast } = useUIStore();

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      disconnect();
    };
  }, []);

  const disconnect = () => {
    if (wsRef.current) {
      try {
        wsRef.current.send(JSON.stringify({ type: 'FinishConnection', data: {} }));
        wsRef.current.close();
      } catch {}
      wsRef.current = null;
    }
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach((t) => t.stop());
      mediaStreamRef.current = null;
    }
    if (audioCtxRef.current && audioCtxRef.current.state !== 'closed') {
      audioCtxRef.current.close();
      audioCtxRef.current = null;
    }
    if (volIntervalRef.current) {
      clearInterval(volIntervalRef.current);
      volIntervalRef.current = null;
    }
    audioQueueRef.current = [];
    isPlayingRef.current = false;
    isPressingRef.current = false;
    setState('idle');
  };

  const connectWebSocket = useCallback(async () => {
    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      // Already connected - send StartSession
      wsRef.current.send(JSON.stringify({ type: 'StartSession', data: {} }));
      return;
    }

    setState('connecting');
    setError('');

    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const wsUrl = `${protocol}//${window.location.host}/api/voice/ws`;

    const ws = new WebSocket(wsUrl);

    ws.onopen = () => {
      console.log('[Voice] WebSocket connected');
      ws.send(JSON.stringify({ type: 'StartSession', data: {} }));
    };

    ws.onmessage = (event) => {
      try {
        const msg = JSON.parse(event.data);
        handleServerMessage(msg);
      } catch (e) {
        console.error('[Voice] Failed to parse message:', e);
      }
    };

    ws.onerror = (e) => {
      console.error('[Voice] WebSocket error:', e);
      setError('连接失败');
      setState('idle');
    };

    ws.onclose = () => {
      console.log('[Voice] WebSocket closed');
      wsRef.current = null;
      if (state !== 'idle') setState('idle');
    };

    wsRef.current = ws;
  }, [state]);

  const handleServerMessage = (msg: any) => {
    switch (msg.type) {
      case 'SessionStarted':
        setState('idle');
        break;
      case 'ASRResponse':
        const text = msg.data?.results?.map((r: any) => r.text).join('') || '';
        if (text) setTranscript((prev) => prev + text);
        break;
      case 'ChatResponse':
        const content = msg.data?.content || '';
        if (content) setResponseText((prev) => prev + content);
        break;
      case 'TTSResponse':
        const audioData = msg.data;
        if (audioData) {
          playAudioBase64(audioData);
        }
        setState('speaking');
        break;
      case 'SessionFinished':
        setState('idle');
        break;
      case 'InterruptAck':
        // Clear audio queue
        audioQueueRef.current = [];
        isPlayingRef.current = false;
        setState('listening');
        break;
      case 'Error':
        setError(msg.data?.message || '发生错误');
        setState('idle');
        break;
    }
  };

  const playAudioBase64 = async (base64Data: string) => {
    if (!audioCtxRef.current || audioCtxRef.current.state === 'closed') {
      try {
        audioCtxRef.current = new AudioContext();
      } catch {
        return;
      }
    }

    try {
      const binaryStr = atob(base64Data);
      const bytes = new Uint8Array(binaryStr.length);
      for (let i = 0; i < binaryStr.length; i++) {
        bytes[i] = binaryStr.charCodeAt(i);
      }
      const audioBuffer = await audioCtxRef.current.decodeAudioData(bytes.buffer);
      audioQueueRef.current.push(audioBuffer);
      playNextInQueue();
    } catch (e) {
      console.error('[Voice] Failed to decode audio:', e);
    }
  };

  const playNextInQueue = () => {
    if (isPlayingRef.current || audioQueueRef.current.length === 0) return;
    if (!audioCtxRef.current || audioCtxRef.current.state === 'closed') return;

    isPlayingRef.current = true;
    const buffer = audioQueueRef.current.shift()!;
    const source = audioCtxRef.current.createBufferSource();
    source.buffer = buffer;
    source.connect(audioCtxRef.current.destination);
    source.onended = () => {
      isPlayingRef.current = false;
      if (audioQueueRef.current.length > 0) {
        playNextInQueue();
      } else {
        setState('listening');
      }
    };
    source.start();
  };

  const startRecording = async () => {
    setError('');
    setTranscript('');
    setResponseText('');

    if (!wsRef.current || wsRef.current.readyState !== WebSocket.OPEN) {
      await connectWebSocket();
      // Wait for connection
      await new Promise((resolve) => setTimeout(resolve, 500));
    }

    if (!wsRef.current || wsRef.current.readyState !== WebSocket.OPEN) {
      setError('无法连接到语音服务');
      setState('idle');
      return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: {
          sampleRate: 16000,
          channelCount: 1,
          echoCancellation: true,
          noiseSuppression: true,
        },
      });
      mediaStreamRef.current = stream;

      const audioCtx = new AudioContext({ sampleRate: 16000 });
      audioCtxRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const processor = audioCtx.createScriptProcessor(4096, 1, 1);
      processorRef.current = processor;

      source.connect(processor);
      processor.connect(audioCtx.destination);

      processor.onaudioprocess = (e) => {
        if (!isPressingRef.current) return;

        const inputData = e.inputBuffer.getChannelData(0);
        // Calculate volume
        let sum = 0;
        for (let i = 0; i < inputData.length; i++) {
          sum += Math.abs(inputData[i]);
        }
        const avg = sum / inputData.length;
        setVolume(Math.min(avg * 5, 1));

        // Convert Float32 to Int16 PCM
        const int16Data = new Int16Array(inputData.length);
        for (let i = 0; i < inputData.length; i++) {
          const s = Math.max(-1, Math.min(1, inputData[i]));
          int16Data[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
        }

        // Send binary audio data
        if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
          wsRef.current.send(int16Data.buffer);
        }
      };

      setState('listening');
      isPressingRef.current = true;
    } catch (e: any) {
      console.error('[Voice] Failed to start recording:', e);
      setError('无法访问麦克风：' + (e.message || '权限被拒绝'));
      setState('idle');
    }
  };

  const stopRecording = () => {
    isPressingRef.current = false;
    setVolume(0);

    // Send EndASR
    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: 'EndASR', data: {} }));
    }

    setState('processing');

    // Stop media stream
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach((t) => t.stop());
      mediaStreamRef.current = null;
    }

    // Disconnect processor
    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }

    if (audioCtxRef.current && audioCtxRef.current.state !== 'closed') {
      audioCtxRef.current.close();
      audioCtxRef.current = null;
    }
  };

  const handleInterrupt = () => {
    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: 'ClientInterrupt', data: {} }));
    }
    audioQueueRef.current = [];
    isPlayingRef.current = false;
    setState('idle');
    setTranscript('');
    setResponseText('');
  };

  const stateLabels: Record<VoiceState, string> = {
    idle: '按住下方按钮开始说话',
    connecting: '连接中…',
    listening: '聆听中…',
    processing: '处理中…',
    speaking: '说话中…',
  };

  const stateColors: Record<VoiceState, string> = {
    idle: 'text-gray-400',
    connecting: 'text-yellow-500',
    listening: 'text-green-500',
    processing: 'text-primary-500',
    speaking: 'text-blue-500',
  };

  return (
    <div className="h-full flex flex-col">
      {/* Status & subtitles */}
      <div className="flex-1 flex flex-col items-center justify-center px-6 text-center">
        <div className={`text-lg font-medium mb-4 ${stateColors[state]}`}>
          {stateLabels[state]}
        </div>

        {error && (
          <div className="text-red-500 text-sm mb-3 bg-red-50 px-4 py-2 rounded-lg">
            {error}
          </div>
        )}

        {/* Volume indicator */}
        {(state === 'listening') && (
          <div className="flex items-center gap-1 mb-4">
            {Array.from({ length: 10 }).map((_, i) => (
              <div
                key={i}
                className="w-1.5 rounded-full transition-all duration-100"
                style={{
                  height: `${8 + Math.random() * 32 * (volume > 0.1 ? volume : 0)}px`,
                  backgroundColor: i / 10 < volume ? '#8b5cf6' : '#e0d5ff',
                  opacity: volume > 0 ? 1 : 0.3,
                }}
              />
            ))}
          </div>
        )}

        {/* Transcript */}
        {(transcript || responseText) && (
          <div className="w-full max-w-md space-y-3">
            {transcript && (
              <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100 text-sm text-left">
                <div className="text-xs text-gray-400 mb-1">你说：</div>
                <div className="text-gray-800">{transcript}</div>
              </div>
            )}
            {responseText && (
              <div className="bg-primary-50 rounded-xl p-4 shadow-sm border border-primary-100 text-sm text-left">
                <div className="text-xs text-primary-400 mb-1">AI：</div>
                <div className="text-gray-800">{responseText}</div>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Bottom controls */}
      <div className="flex-shrink-0 flex flex-col items-center pb-8 pt-4">
        {/* Interrupt button (visible during speaking) */}
        {state === 'speaking' && (
          <button
            onClick={handleInterrupt}
            className="mb-4 px-5 py-2 rounded-full bg-red-100 text-red-600 text-sm font-medium hover:bg-red-200 transition-colors"
          >
            打断
          </button>
        )}

        {/* Main push-to-talk button */}
        <button
          onMouseDown={startRecording}
          onMouseUp={stopRecording}
          onMouseLeave={(e) => {
            if (isPressingRef.current) stopRecording();
          }}
          onTouchStart={(e) => {
            e.preventDefault();
            startRecording();
          }}
          onTouchEnd={(e) => {
            e.preventDefault();
            stopRecording();
          }}
          className={`w-20 h-20 md:w-[100px] md:h-[100px] rounded-full flex items-center justify-center transition-all duration-200 select-none ${
            state === 'listening'
              ? 'bg-red-500 shadow-lg shadow-red-300 scale-110'
              : state === 'connecting' || state === 'processing'
              ? 'bg-yellow-400 shadow-lg shadow-yellow-200'
              : state === 'speaking'
              ? 'bg-blue-500 shadow-lg shadow-blue-300'
              : 'bg-primary-500 shadow-lg shadow-primary-300 hover:shadow-xl hover:scale-105'
          }`}
          disabled={state === 'connecting'}
        >
          <svg className="w-10 h-10 md:w-12 md:h-12 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            {state === 'listening' ? (
              // Show recording indicator
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            ) : (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            )}
          </svg>
        </button>

        <p className="text-xs text-gray-400 mt-4">
          {state === 'idle' ? '按住 说话' : '松手 结束'}
        </p>
      </div>
    </div>
  );
}

input.newString:
.bounce-dot:nth-child(1) { animation-delay: -0.32s; }
.bounce-dot:nth-child(2) { animation-delay: -0.16s; }

/* Slide up animation for modals */
@keyframes slideUp {
  from { transform: translateY(100%); opacity: 0; }
  to { transform: translateY(0); opacity: 1; }
